In the next days I'll work on it. It is important to be as strict as possible to the specs 😄 

I would ask you to confirm if my understanding is correct.

According to the swagger specs below:
* the parameters defined for ``/example1`` are ``sec1`` as required
* the parameters defined for ``/example2`` are ``sec1`` as required and ``sec2`` as optional. Well defined requests have ``sec1`` only or ``sec1`` and ``sec2`` in the header.
* the parameters defined for ``/example2`` are ``sec1`` as required and ``sec2``, ``sec3`` as optional. Well defined requests have ``sec1`` only or ``sec1`` and ``sec2`` or ``sec1`` and ``sec3``  in the header. ``sec2`` and ``sec3`` cannot be present at the same time in the header.
```json
{
  "swagger": "2.0",
  "info": {"title": "Test","version": "1.0"},
  "securityDefinitions": {
    "sec1": {
      "type": "apiKey",
      "name": "sec1",
      "in": "header"
    },
    "sec2": {
      "type": "apiKey",
      "name": "sec2",
      "in": "header"
    },
    "sec3": {
      "type": "apiKey",
      "name": "sec3",
      "in": "header"
    }
  },
  "security": [
    {
      "sec1": []
    }
  ],
  "paths": {
    "/example1": {
      "get": {
        "description": "Endpoint requires sec1 header parameter",
        "responses": {"200": {"description": "OK"}}
      }
    },
    "/example2": {
      "get": {
        "description": "Endpoint requires sec1 header parameter and optionally sec2 header parameter",
        "security": [
          {"sec2": []}
        ],
        "responses": {"200": {"description": "OK"}}
        }
    },
    "/example3": {
      "get": {
        "description": "Endpoint requires sec1 header parameter and optionally sec2 or sec3 header parameter",
        "security": [
          {"sec2": []},
          {"sec3": []}
        ],
        "responses": {"200": {"description": "OK"}}
      }
    }
  }
}
```

